import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {

const [messages,setMessages]=useState([]);
const [input,setInput]=useState("");
const [loading,setLoading]=useState(false);

const sendMessage = async () => {

if(!input.trim()) return;

const userMsg={
role:"user",
text:input
};

setMessages(prev=>[...prev,userMsg]);
setInput("");
setLoading(true);

try{

const res = await axios.post(
"http://localhost:5003/chat",
{message:input}
);

const aiMsg={
role:"ai",
text:res.data.reply
};

setMessages(prev=>[...prev,aiMsg]);

}catch{

setMessages(prev=>[
...prev,
{role:"ai",text:"AI Error"}
]);

}

setLoading(false);

};

return(

<div className="app">

{/* LEFT SIDEBAR */}

<div className="sidebar">

<h2 className="logo">🤖 AI Chatbot</h2>

<div className="sidebar-section">

<h4>Conversations</h4>

<div className="conversation active">
what is API
<span>2 messages</span>
</div>

<button className="new-chat">
+ New Chat
</button>

</div>

<div className="sidebar-section">

<h4>Memory Stats</h4>

<p>Knowledge: 5 topics</p>
<p>Facts: 2 stored</p>
<p>Chats: {messages.length}</p>

<button className="clear-memory">
Clear All Memory
</button>

</div>

</div>

{/* CENTER CHAT */}

<div className="chat-area">

<div className="chat-header">
🤖 AI Chatbot
</div>

<div className="memory-tabs">

<span className="tab active">Semantic</span>
<span className="tab">Episodic</span>
<span className="tab">Procedural</span>
<span className="tab">Emotional</span>

</div>

<div className="messages">

{messages.map((msg,i)=>(
<div
key={i}
className={msg.role==="user"?"user-msg":"ai-msg"}
>
{msg.text}
</div>
))}

{loading && <div className="ai-msg">AI thinking...</div>}

</div>

<div className="input-bar">

<input
value={input}
onChange={(e)=>setInput(e.target.value)}
placeholder="Message AI Chatbot..."
/>

<button onClick={sendMessage}>
Send
</button>

</div>

</div>

{/* RIGHT PANEL */}

<div className="memory-panel">

<h3>SEMANTIC MEMORY</h3>

<div className="card">

<h4>Available Topics</h4>

<div className="tags">

<span>Machine Learning</span>
<span>AI</span>
<span>Python</span>
<span>Databases</span>

</div>

<p className="small">
5 topics in knowledge base
</p>

</div>

<h3>USER PROFILE</h3>

<div className="card">

<p>
Start chatting to build your profile.  
Share information about yourself and I'll remember it.
</p>

</div>

<h3>EMOTIONAL CONDITIONING</h3>

<div className="card">

<p>
What do you like? Share your likes to shape my emotional responses.
</p>

</div>

</div>

</div>

);

}

export default App;
